{
  "processing_config": {
    "version": 2,
    "taxonomy_notes": "Top-level categories are broad, multi-label buckets. Subtypes refine within each top-level. Attributes capture cross-cutting signals (e.g., urgency, explicitness).",
    "settings": {
      "initialization": {
        "apply_hard_assertions": true,
        "seed_category_scores": true
      },
      "rule_scoring": {
        "use_lexical_patterns": true,
        "apply_subtype_rules": true,
        "bounded_aggregation": true
      },
      "attribute_processing": {
        "detect_self_sent": true,
        "resolve_domains": true,
        "derive_context_flags": true
      },
      "attribute_influence": {
        "apply_bonuses": true,
        "apply_penalties": true,
        "enforce_caps": true
      },
      "disambiguation": {
        "pairwise_adjustments": true,
        "confidence_gap_threshold": 2
      },
      "multi_label_selection": {
        "max_labels": 3,
        "min_secondary_confidence": 8,
        "allowed_combinations": ["financial+actionable"]
      },
      "ai_routing": {
        "high_confidence_threshold": 15,
        "ai_required_threshold": 12,
        "skip_ai_conditions": ["hard_assertion"]
      }
    },
    "category_signals": {
      "financial": {
        "hard_assertions": {
          "from_domains_ref": { "source_group": "financial", "confidence": "high" },
          "subject_prefixes": [
            "Your statement is ready",
            "Monthly statement",
            "Account statement",
            "Important account alert"
          ]
        },
        "strong_indicators": {
          "from_domains_ref": { "source_group": "financial", "confidence": "medium" },
          "subject_contains": ["invoice", "receipt", "payment posted", "card purchase", "transaction alert"],
          "body_contains": ["amount due", "invoice number", "due date", "posted to your account"]
        },
        "disambiguators": {
          "boost_if_present_attributes": ["has_amount"],
          "suppress_if_body_contains": ["unsubscribe", "sale ends"]
        }
      },
      "travel": {
        "hard_assertions": {
          "from_addresses": [
            "noreply-travel@google.com",
            "itinerary@expedia.com",
            "itinerary@travelport.com",
            "confirmation@booking.com",
            "notifications@aa.com",
            "notifications@delta.com"
          ],
          "subject_prefixes": [
            "Your tracked flight to",
            "Flight update",
            "Itinerary for",
            "Your booking confirmation",
            "Boarding pass"
          ]
        },
        "strong_indicators": {
          "subject_contains": [
            "boarding pass",
            "gate change",
            "flight delayed",
            "flight cancellation",
            "check-in reminder"
          ],
          "body_contains": [
            "PNR",
            "confirmation number",
            "booking reference",
            "departure",
            "arrival gate",
            "seat number"
          ]
        },
        "disambiguators": {
          "boost_if_absent_categories": ["commerce_logistics"],
          "suppress_if_body_contains": ["order shipped"]
        }
      }
    },
    "confidence_thresholds": {
      "high_confidence": 15,
      "medium_confidence": 8,
      "low_confidence": 3,
      "ai_classification_required": 12,
      "manual_review_required": 3,
      "secondary_label_min_gap": 2
    },
    "multi_label_policy": {
      "max_top_level_labels": 3,
      "min_confidence_for_additional": 6,
      "min_delta_primary_secondary": 2,
      "allow_financial_actionable_copresence": true
    },
    "domain_signal_overrides": {
      "financial": {
        "hard_include": [],
        "hard_exclude": [],
        "strong_include": [],
        "strong_exclude": []
      }
    },
    "domain_signal_resolution": {
      "mode": "runtime_resolved",
      "source": "config/domain-sources.json",
      "notes": "from_domains_ref entries are materialized at load time via domainResolver; do not edit from_domains arrays directly."
    },
    "top_level_categories": {
      "financial": {
        "description": "Financial communications: transactions, statements, bills, invoices, accounts receivable, accounts payable, receipts, investment updates, payment confirmations.",
        "subtypes": {
          "receipt": {
            "description": "Purchase receipts / confirmations with itemized or total amounts.",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["receipt", "payment confirmation", "order confirmation"],
                  "weight": 12
                }
              ],
              "medium_confidence": [
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["total", "amount", "charged", "paid"],
                  "weight": 6
                }
              ]
            }
          },
          "invoice": {
            "description": "Invoices issued requesting payment or documenting billing.",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["invoice", "tax invoice"],
                  "weight": 12
                }
              ],
              "medium_confidence": [
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["invoice number", "amount due"],
                  "weight": 6
                }
              ]
            }
          },
          "bill_due": {
            "description": "Bills or statements indicating an upcoming or due payment.",
            "rule_based_classification": {
              "medium_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["bill", "due", "due soon"],
                  "weight": 8
                }
              ]
            }
          },
          "statement": {
            "description": "Periodic financial statements (bank, credit card, account summaries).",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["statement", "account summary", "monthly statement"],
                  "weight": 12
                }
              ]
            }
          },
          "transaction_alert": {
            "description": "Alerts about recent transactions or balance changes.",
            "rule_based_classification": {
              "medium_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["transaction", "purchase", "charge", "alert"],
                  "weight": 8
                }
              ]
            }
          },
          "investment_update": {
            "description": "Portfolio or investment performance updates.",
            "rule_based_classification": {
              "medium_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["portfolio", "holdings", "investment", "performance"],
                  "weight": 8
                }
              ]
            }
          }
        },
        "ai_final_classification": {
          "category_description": "Financial & transactional emails including receipts, invoices, bills, statements, alerts, and investment updates.",
          "decision_criteria": [
            "Does the email reference monetary amounts or account activity?",
            "Does it confirm or request payment?",
            "Is it a periodic financial statement or update?"
          ]
        }
      },
      "actionable": {
        "description": "Emails that require or request action, response, decision, or follow-up (explicit or implicit).",
        "subtypes": {
          "explicit_action": {
            "description": "Clear task assignments or explicit directives.",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "subject",
                  "operation": "starts_with",
                  "values": ["TODO:", "ACTION:", "TASK:", "REMINDER:", "DO:"],
                  "weight": 15
                },
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["action required", "please review", "needs attention"],
                  "weight": 12
                }
              ]
            }
          },
          "implicit_action": {
            "description": "Questions or indirect requests implying a need for response or input.",
            "rule_based_classification": {
              "medium_confidence": [
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["can you", "could you", "would you mind", "please let me know"],
                  "weight": 7
                },
                {
                  "field": "subject",
                  "operation": "ends_with",
                  "values": ["?"],
                  "weight": 4
                }
              ],
              "low_confidence": [
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["thoughts?", "your feedback", "your input", "what do you think"],
                  "weight": 3
                }
              ]
            }
          }
        },
        "ai_final_classification": {
          "category_description": "Action-required emails (explicit or implicit).",
          "decision_criteria": [
            "Is there a direct request or instruction?",
            "Is a response expected?",
            "Would inaction cause a problem (deadline, social obligation)?"
          ]
        }
      },
      "subscription_content": {
        "description": "Recurring informational content from subscribed sources (newsletters, digests, curated educational content).",
        "subtypes": {
          "newsletter": {
            "description": "Standard newsletter issues from a publication or author.",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["newsletter", "digest", "weekly", "daily brief"],
                  "weight": 12
                }
              ],
              "medium_confidence": [
                {
                  "field": "headers.list-unsubscribe",
                  "operation": "exists",
                  "weight": 6
                }
              ],
              "low_confidence": [
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["unsubscribe", "manage preferences", "view in browser"],
                  "weight": 3
                }
              ]
            }
          },
          "digest": {
            "description": "Summarized multi-topic updates (weekly/monthly digests)."
          },
          "curated_links": {
            "description": "Collections of recommended or curated links."
          },
          "learning_series": {
            "description": "Sequential educational lesson emails."
          }
        },
        "ai_final_classification": {
          "category_description": "Subscription-based informational content (curated or educational).",
          "decision_criteria": [
            "Is primary intent to inform or educate?",
            "Is there evidence of periodic publication?",
            "Does formatting indicate multi-section or curated content?"
          ],
          "exclusion_criteria": ["Primarily promotional sales content"]
        }
      },
      "commerce_logistics": {
        "description": "Commerce order lifecycle and logistics: order confirmations, shipping, delivery, returns, exceptions.",
        "subtypes": {
          "order_confirmation": {
            "description": "Order placed acknowledgements without shipping yet.",
            "rule_based_classification": {
              "medium_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["order confirmation", "order received"],
                  "weight": 8
                }
              ]
            }
          },
          "shipping_update": {
            "description": "In-transit updates and tracking info.",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": [
                    "shipped",
                    "delivered",
                    "out for delivery",
                    "tracking number",
                    "delivery update",
                    "package arrived"
                  ],
                  "weight": 12
                }
              ],
              "medium_confidence": [
                {
                  "field": "subject",
                  "operation": "contains_any",
                  "values": ["order", "shipment", "delivery", "package", "parcel", "dispatch"],
                  "weight": 7
                },
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["tracking number", "track your package", "estimated delivery", "delivery date", "carrier"],
                  "weight": 6
                }
              ],
              "low_confidence": [
                {
                  "field": "body",
                  "operation": "contains_any",
                  "values": ["shipped to", "delivery address", "in transit", "on the way"],
                  "weight": 3
                }
              ]
            }
          },
          "delivery_event": {
            "description": "Delivered / arrival confirmations."
          },
          "delay_exception": {
            "description": "Delay or exception notices requiring awareness."
          },
          "return_authorization": {
            "description": "Return labels or authorization workflow emails."
          }
        },
        "ai_final_classification": {
          "category_description": "Order lifecycle & logistics communications.",
          "decision_criteria": [
            "Does it reference shipping or delivery state?",
            "Is tracking or carrier info present?",
            "Is user action required for delivery or return?"
          ]
        }
      },
      "personal": {
        "description": "Personal communications: self notes, family, close personal contacts.",
        "subtypes": {
          "self_note": {
            "description": "Self-sent reminders or notes (derived via self_sent attribute).",
            "derived": true,
            "derivation_logic": "if attributes.self_sent == true and no other personal subtype outranks"
          },
          "family": {
            "description": "Family member communications.",
            "rule_based_classification": {
              "high_confidence": [
                {
                  "field": "from.address",
                  "operation": "contains_any",
                  "values": [
                    "meganhamilton13@gmail.com",
                    "katierosehamilton@gmail.com",
                    "lydiagracehamilton@gmail.com"
                  ],
                  "weight": 15
                }
              ],
              "medium_confidence": [
                {
                  "field": "from.name",
                  "operation": "contains_any",
                  "values": ["hamilton"],
                  "weight": 10
                }
              ]
            }
          },
          "close_contact": {
            "description": "Other trusted personal contacts (future expansion)."
          }
        },
        "ai_final_classification": {
          "category_description": "Personal & family-oriented communication.",
          "decision_criteria": [
            "Is sender a known personal identity?",
            "Is tone informal/personal?",
            "Does content relate to personal life or relationships?"
          ]
        }
      },
      "account_security": {
        "description": "Account or security related alerts, password resets, login notifications.",
        "subtypes": {
          "login_alert": { "description": "New login / sign-in notification." },
          "password_reset": {
            "description": "Password reset or credential change request."
          },
          "security_notice": {
            "description": "Security advisory or policy update."
          }
        }
      },
      "system_notifications": {
        "description": "Service/platform system operational notifications.",
        "subtypes": {
          "feature_change": {
            "description": "Feature or product update announcement."
          },
          "quota_warning": { "description": "Usage or quota nearing limits." },
          "service_status": {
            "description": "Status / uptime / incident communication."
          }
        }
      },
      "travel": {
        "description": "Travel itineraries, booking confirmations, and transport updates (flights, hotels, trip modifications).",
        "subtypes": {
          "flight_itinerary": {
            "description": "Initial flight booking or full itinerary document."
          },
          "flight_alert": {
            "description": "Gate / delay / cancellation / boarding updates."
          },
          "hotel_booking": {
            "description": "Hotel reservation confirmations and modifications."
          },
          "trip_update": {
            "description": "Aggregated or modified multi-segment trip updates."
          }
        },
        "ai_final_classification": {
          "category_description": "Transportation & lodging logistics including bookings, itineraries, and operational flight/hotel alerts.",
          "decision_criteria": [
            "Does it contain itinerary or booking identifiers (PNR, confirmation)?",
            "Is there flight, hotel, or segment timing information?",
            "Is this an operational status change (delay, gate, cancellation)?"
          ],
          "exclusion_criteria": [
            "Generic calendar invites (should be scheduling_events)",
            "E-commerce shipping (belongs to commerce_logistics)"
          ]
        }
      },
      "scheduling_events": {
        "description": "Calendar & event logistics (invites, updates). Travel-related items moved to top-level 'travel' category.",
        "subtypes": {
          "calendar_invite": { "description": "Meeting or event invitation." },
          "event_update": { "description": "Change to scheduled event." }
        }
      },
      "marketing_promotions": {
        "description": "Promotional or sales-oriented content (optional suppression).",
        "suppression_default": true,
        "subtypes": {
          "promo_offer": { "description": "General promotional offer email." },
          "sale_alert": { "description": "Sale / discount announcement." }
        }
      },
      "uncategorized": {
        "description": "Fallback when no confident category applies.",
        "subtypes": {
          "needs_review": { "description": "Manual review required." }
        }
      }
    },
    "attributes": {
      "schema": {
        "explicitness": {
          "type": "enum",
          "values": ["explicit", "implicit"],
          "description": "Nature of action request if actionable."
        },
        "urgency": {
          "type": "enum",
          "values": ["none", "low", "medium", "high"],
          "description": "Relative urgency derived from language & deadlines."
        },
        "requires_action": { "type": "boolean" },
        "has_amount": { "type": "boolean" },
        "has_due_date": { "type": "boolean" },
        "tracking_present": { "type": "boolean" },
        "delivery_phase": {
          "type": "enum",
          "values": ["pre_shipment", "in_transit", "out_for_delivery", "delivered", "exception"],
          "description": "Logistics phase when commerce_logistics present."
        },
        "unsubscribe_present": { "type": "boolean" },
        "cadence": {
          "type": "enum",
          "values": ["daily", "weekly", "monthly", "irregular"],
          "description": "Heuristic cadence for subscription content."
        },
        "self_sent": {
          "type": "boolean",
          "description": "Email sent exclusively from user to self (all recipients are user addresses). Derived logically; no pattern detector."
        },
        "from_financial_institution": {
          "type": "boolean",
          "description": "Sender domain/address matches known financial institution list."
        },
        "financial_institution_type": {
          "type": "enum",
          "values": ["bank", "card", "investment", "payment_processor"],
          "description": "Institution classification derived from domain list when from_financial_institution is true."
        },
        "from_newsletter_source": {
          "type": "boolean",
          "description": "Sender domain/address or List-Id matches curated newsletter source list."
        },
        "from_logistics_carrier": {
          "type": "boolean",
          "description": "Sender domain/address matches known logistics carrier or marketplace list."
        }
      },
      "detectors": [
        {
          "attribute": "has_amount",
          "field": "body",
          "operation": "regex_any",
          "values": ["\\$\\d+", "USD", "amount due"]
        },
        {
          "attribute": "has_due_date",
          "field": "body",
          "operation": "contains_any",
          "values": ["due by", "due on", "due date", "pay by", "payment due"]
        },
        {
          "attribute": "requires_action",
          "field": "body",
          "operation": "contains_any",
          "values": ["please review", "action required", "respond", "reply", "follow up"]
        },
        {
          "attribute": "tracking_present",
          "field": "body",
          "operation": "contains_any",
          "values": ["tracking number", "track your package"]
        },
        {
          "attribute": "unsubscribe_present",
          "field": "body",
          "operation": "contains_any",
          "values": ["unsubscribe", "manage preferences"]
        }
      ],
      "derived": {
        "self_sent": {
          "logic": "from.address in user_addresses AND all(to+cc+bcc) in user_addresses AND NOT headers['List-Id']",
          "notes": "Used to auto-derive personal.self_note subtype when no stronger personal subtype matches."
        },
        "from_financial_institution": {
          "logic": "base_domain(from.address) in domain_sources.financial.domains",
          "notes": "financial_institution_type taken from domain metadata."
        },
        "from_newsletter_source": {
          "logic": "base_domain(from.address) in domain_sources.newsletter.domains OR headers['List-Id'] present",
          "notes": "List-Id presence alone does not force newsletter if strong promotional patterns dominate."
        },
        "from_logistics_carrier": {
          "logic": "base_domain(from.address) in domain_sources.logistics.domains",
          "notes": "Used to boost commerce_logistics; does not override travel flight contexts."
        }
      },
