/**
 * EmailCategorizer Node: AI Routing Decision
 *
 * PURPOSE
 *  Stage 8 of the EmailCategorizer pipeline. Determines whether emails need AI classification
 *  based on confidence scores from multi-label selection. Routes high-confidence emails directly
 *  to final decision while sending uncertain cases through AI classification for enhancement.
 *
 * PROCESSING LOGIC
 *  1. Load configuration and input email data with selected labels and confidence scores
 *  2. Analyze confidence levels of selected labels against AI routing thresholds
 *  3. Route high-confidence classifications (>=15) directly to merge/final decision
 *  4. Route uncertain classifications (3-12 range) to AI classification node
 *  5. Route very low confidence (<3) directly to final decision as unclassifiable
 *
 * DATABASE OPERATIONS
 *  - None (pure business logic node)
 *  - Database persistence handled by separate prepare_ai_routing_persistence node
 *
 * EXPECTED INPUT (from MultiLabelSelectionNode)
 *  Array of email objects with:
 *  - gmail_id, session_id, selected_labels with confidence scores
 *  - candidate_scores: {category_id: {score, confidence, decision, ...}}
 *  - needs_ai_classification: boolean (preliminary assessment)
 *  - selection_summary: {total_labels, primary_category, confidence_range, ...}
 *
 * OUTPUT FORMAT
 *  Email objects routed for appropriate next stage:
 *  [{
 *    gmail_id: string,
 *    session_id: string,
 *    selected_labels: [...], // preserved from previous stage
 *    candidate_scores: {...}, // preserved for potential AI processing
 *    ai_routing_decision: {
 *      route_to_ai: boolean,
 *      routing_reason: string,
 *      confidence_assessment: string,
 *      cost_consideration: string
 *    },
 *    routing_branch: "ai_classification" | "direct_to_merge",
 *    // ... original email fields
 *  }]
 *
 * CONFIGURATION DEPENDENCIES
 *  - config.ai_routing_config.confidence_thresholds (high_skip_ai, medium_route_ai, low_skip_ai)
 *  - config.confidence_thresholds (reused for consistency with other stages)
 *
 * ROUTING DECISION LOGIC
 *  - High Confidence (>=15): Skip AI - rule-based results are reliable
 *  - Medium Confidence (3-14): Route to AI - can benefit from enhanced classification
 *  - Very Low Confidence (<3): Skip AI - likely unclassifiable even with AI
 *  - No Labels Selected: Route to AI - last chance for classification
 *
 * BRANCHING OUTPUT
 *  This node creates two output branches in n8n:
 *  - Branch 0: Emails needing AI classification → routes to ai_classification node
 *  - Branch 1: Emails with sufficient confidence → routes to merge_classifications node
 *
 * Extends CodeNode from n8n-simulator for local testing and development.
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class AIRoutingNode extends CodeNode {
  constructor() {
    super('AIRouting');
  }

  execute($input) {
    const inputItems = $input.all();
    console.log('Starting ai_routing_check node execution');

    // Load cached configuration
    const staticData = $getWorkflowStaticData('global');
    const config = staticData.email_categorizer_config?.config;
    if (!config) {
      throw new Error('Email categorizer configuration not found in static data');
    }

    const aiRoutingConfig = config.ai_routing_config || {};
    const confidenceThresholds = config.confidence_thresholds || {};

    // Extract routing thresholds with defaults
    const highConfidenceSkipAI = aiRoutingConfig.high_confidence_skip_ai || confidenceThresholds.high_confidence || 15;
    const mediumConfidenceRouteAI =
      aiRoutingConfig.medium_confidence_route_ai || confidenceThresholds.medium_confidence || 8;
    const lowConfidenceSkipAI = aiRoutingConfig.low_confidence_skip_ai || confidenceThresholds.low_confidence || 3;

    console.log(`AI routing processing ${inputItems.length} emails`);
    console.log(
      `Routing thresholds - High: ${highConfidenceSkipAI} (skip AI), Medium: ${mediumConfidenceRouteAI} (route to AI), Low: ${lowConfidenceSkipAI} (skip AI)`
    );

    const aiRoutingResults = [];
    const directResults = [];
    let aiRoutingCount = 0;
    let directRoutingCount = 0;

    for (const item of inputItems) {
      const emailData = item.json;
      console.log(`Processing AI routing decision for email ${emailData.gmail_id}`);

      try {
        // Analyze confidence levels and make routing decision
        const routingDecision = this._makeRoutingDecision(
          emailData.selected_labels || [],
          emailData.candidate_scores || {},
          highConfidenceSkipAI,
          mediumConfidenceRouteAI,
          lowConfidenceSkipAI
        );

        // Add routing decision data to email (no database operations)
        const routedEmailData = {
          ...emailData,
          ai_routing_decision: routingDecision,
          routing_branch: routingDecision.route_to_ai ? 'ai_classification' : 'direct_to_merge',
          // Add data for database persistence preparation
          _persistence_data: {
            stage_type: 'ai_routing_check',
            stage_order: 8,
            routing_decision: routingDecision,
            session_updates: {
              ai_routing_used: routingDecision.route_to_ai,
              ai_routing_reason: routingDecision.routing_reason,
              ai_routing_confidence_assessment: routingDecision.confidence_assessment,
            },
          },
        };

        // Route to appropriate output branch
        if (routingDecision.route_to_ai) {
          aiRoutingResults.push({ json: routedEmailData });
          aiRoutingCount++;
          console.log(`Email ${emailData.gmail_id} routed to AI classification: ${routingDecision.routing_reason}`);
        } else {
          directResults.push({ json: routedEmailData });
          directRoutingCount++;
          console.log(`Email ${emailData.gmail_id} routed directly to merge: ${routingDecision.routing_reason}`);
        }
      } catch (error) {
        console.error(`Error processing AI routing for email ${emailData.gmail_id}:`, error);
        // On error, route to direct merge to avoid blocking pipeline
        const errorEmailData = {
          ...emailData,
          ai_routing_error: error.message,
          ai_routing_decision: {
            route_to_ai: false,
            routing_reason: `Error in routing decision: ${error.message}`,
            confidence_assessment: 'error',
            cost_consideration: 'error_bypass',
          },
          routing_branch: 'direct_to_merge',
        };
        directResults.push({ json: errorEmailData });
        directRoutingCount++;
      }
    }

    console.log(`AI routing completed - ${aiRoutingCount} emails to AI, ${directRoutingCount} emails direct to merge`);

    // In n8n, this would return multiple output branches
    // For simulator, we'll return a combined result with routing indicators
    const allResults = [
      ...aiRoutingResults.map((item) => ({
        ...item,
        json: { ...item.json, _output_branch: 0 },
      })),
      ...directResults.map((item) => ({
        ...item,
        json: { ...item.json, _output_branch: 1 },
      })),
    ];

    console.log(`Total routing results: ${allResults.length} emails processed`);
    return allResults;
  }

  /**
   * Make routing decision based on confidence levels and selection quality
   */
  _makeRoutingDecision(
    selectedLabels,
    candidateScores,
    highConfidenceSkipAI,
    mediumConfidenceRouteAI,
    lowConfidenceSkipAI
  ) {
    // Case 1: No labels selected - route to AI for last chance classification
    if (selectedLabels.length === 0) {
      return {
        route_to_ai: true,
        routing_reason: 'No labels selected - AI classification may recover classification',
        confidence_assessment: 'no_classification',
        cost_consideration: 'recovery_attempt',
      };
    }

    // Case 2: Check primary label confidence
    const primaryLabel = selectedLabels.find((label) => label.is_primary) || selectedLabels[0];
    const primaryScore = primaryLabel.score;

    // High confidence - skip AI (rule-based results are reliable)
    if (primaryScore >= highConfidenceSkipAI) {
      return {
        route_to_ai: false,
        routing_reason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
        confidence_assessment: 'high_confidence',
        cost_consideration: 'ai_unnecessary',
      };
    }

    // Very low confidence - skip AI (likely unclassifiable)
    if (primaryScore < lowConfidenceSkipAI) {
      return {
        route_to_ai: false,
        routing_reason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
        confidence_assessment: 'very_low_confidence',
        cost_consideration: 'ai_ineffective',
      };
    }

    // Medium confidence range - analyze further for AI routing decision
    const hasMultipleLabels = selectedLabels.length > 1;

    // Check if any candidate categories are close competitors
    const hasCloseCompetitors = this._hasCloseCompetitors(candidateScores, primaryScore, 3);

    // Route to AI if in uncertain range and conditions suggest AI could help
    if (primaryScore >= lowConfidenceSkipAI && primaryScore < highConfidenceSkipAI) {
      let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
      let shouldRouteToAI = true;
      let costConsideration = 'beneficial_enhancement';

      // Additional factors for AI routing decision
      if (hasMultipleLabels) {
        aiRoutingReason += ' with multiple labels selected';
        costConsideration = 'multi_label_validation';
      }

      if (hasCloseCompetitors) {
        aiRoutingReason += ' with close competing categories';
        costConsideration = 'disambiguation_valuable';
      }

      // Conservative approach: medium confidence usually benefits from AI
      if (primaryScore >= mediumConfidenceRouteAI) {
        return {
          route_to_ai: shouldRouteToAI,
          routing_reason: aiRoutingReason + ' - AI classification can improve accuracy',
          confidence_assessment: 'medium_confidence',
          cost_consideration: costConsideration,
        };
      } else {
        return {
          route_to_ai: false,
          routing_reason: aiRoutingReason + ' but below AI routing threshold - accept rule-based result',
          confidence_assessment: 'low_medium_confidence',
          cost_consideration: 'cost_threshold_not_met',
        };
      }
    }

    // Default case (shouldn't reach here with proper thresholds)
    return {
      route_to_ai: false,
      routing_reason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
      confidence_assessment: 'unclear',
      cost_consideration: 'default_conservative',
    };
  }

  /**
   * Check if there are close competing categories that AI could help disambiguate
   */
  _hasCloseCompetitors(candidateScores, primaryScore, competitorGap = 3) {
    const competitors = Object.entries(candidateScores)
      .map(([categoryCode, scoreData]) => ({
        category: categoryCode,
        score: scoreData.score || 0,
      }))
      .filter((cat) => cat.score > 0 && cat.score < primaryScore)
      .filter((cat) => primaryScore - cat.score <= competitorGap);

    const hasCompetitors = competitors.length > 0;
    if (hasCompetitors) {
      console.log(
        `Found ${competitors.length} close competitors: ${competitors
          .map((c) => `${c.category}:${c.score}`)
          .join(', ')}`
      );
    }

    return hasCompetitors;
  }
}

