      expect(result.explainability_trace.stage_order).toBe(8);
      expect(result.explainability_trace.decision_factors).toHaveProperty('primary_score');
      expect(result.explainability_trace.decision_factors).toHaveProperty('threshold_analysis');
      expect(result.explainability_trace.decision_factors).toHaveProperty('competitor_analysis');
      expect(result.explainability_trace.reasoning).toBeDefined();
      expect(result.explainability_trace.processing_metadata).toHaveProperty('processing_time_ms');
    });

    it('should include threshold configuration in trace', () => {
      const classification: EmailClassification = {
        gmail_id: 'test-123',
        session_id: 'session-123',
        selected_labels: [
          {
            category: 'subscription_content',
            confidence: 13.0,
            is_primary: true,
            subtype: 'newsletter',
            reasoning: 'Newsletter classification'
          }
        ],
        candidate_scores: {
          subscription_content: { score: 13.0, confidence: 13.0, decision: 'selected' }
        }
      };

      const result = aiRoutingStage(mockEmail, mockSession, classification, mockConfig);

      expect(result.explainability_trace.decision_factors.threshold_analysis).toEqual({
        high_confidence_threshold: 15,
        ai_required_threshold: 12,
        low_confidence_threshold: 3,
        primary_score: 13.0,
        threshold_met: 'ai_required'
      });
    });
  });

  describe('Performance Requirements', () => {
    it('should process routing decision in under 50ms', () => {
      const classification: EmailClassification = {
        gmail_id: 'test-123',
        session_id: 'session-123',
        selected_labels: [
          {
            category: 'financial',
            confidence: 12.5,
            is_primary: true,
            subtype: 'receipt',
            reasoning: 'Performance test classification'
          }
        ],
        candidate_scores: {
          financial: { score: 12.5, confidence: 12.5, decision: 'selected' }
        }
      };

      const startTime = Date.now();
      const result = aiRoutingStage(mockEmail, mockSession, classification, mockConfig);
      const endTime = Date.now();

      const processingTime = endTime - startTime;
      expect(processingTime).toBeLessThan(50);
      expect(result.explainability_trace.processing_metadata.processing_time_ms).toBeLessThan(50);
    });

    it('should handle large candidate score sets efficiently', () => {
      const largeCandidateScores: Record<string, any> = {};
      for (let i = 0; i < 100; i++) {
        largeCandidateScores[`category_${i}`] = {
          score: Math.random() * 10,
          confidence: Math.random() * 10,
          decision: 'candidate'
        };
      }

      const classification: EmailClassification = {
        gmail_id: 'test-123',
        session_id: 'session-123',
        selected_labels: [
          {
            category: 'financial',
            confidence: 12.0,
            is_primary: true,
            subtype: 'receipt',
            reasoning: 'Large dataset test'
          }
        ],
        candidate_scores: largeCandidateScores
      };

      const startTime = Date.now();
      const result = aiRoutingStage(mockEmail, mockSession, classification, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(100);
      expect(result.routing_decision).toBeDefined();
    });
  });
});

