     1→/**
     2→ * Multi-Label Selection Stage
     3→ *
     4→ * Implements sophisticated multi-label selection logic based on ranking algorithms,
     5→ * confidence thresholds, co-presence rules, and AI routing decisions.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Ranking categories by final scores
     9→ * - Selecting primary and secondary labels based on confidence and gap thresholds
    10→ * - Enforcing co-presence rules and allowed combinations
    11→ * - Determining AI classification requirements
    12→ * - Generating complete selection rationale and audit trails
    13→ */
    14→
    15→import {
    16→  CategoryScore,
    17→  MultiLabelConfig,
    18→  ConfidenceThresholds,
    19→  SelectedLabel,
    20→  SelectionSummary,
    21→  MultiLabelSelectionResult,
    22→} from './types';
    23→
    24→export class MultiLabelSelectionStage {
    25→  private config: MultiLabelConfig;
    26→  private thresholds: ConfidenceThresholds;
    27→
    28→  constructor(config: MultiLabelConfig, thresholds: ConfidenceThresholds) {
    29→    this.validateConfiguration(config, thresholds);
    30→    this.config = config;
    31→    this.thresholds = thresholds;
    32→  }
    33→
    34→  /**
    35→   * Validate configuration parameters
    36→   */
    37→  private validateConfiguration(config: MultiLabelConfig, thresholds: ConfidenceThresholds): void {
    38→    if (config.maxLabels < 0) {
    39→      throw new Error('Invalid configuration: maxLabels cannot be negative');
    40→    }
