/**
 * AI Routing Stage
 *
 * Stage 8 of the EmailCategorizer pipeline. Determines whether emails need AI classification
 * based on confidence scores from multi-label selection. Routes high-confidence emails directly
 * to final decision while sending uncertain cases through AI classification for enhancement.
 *
 * ROUTING DECISION LOGIC:
 * - High Confidence (>=15): Skip AI - rule-based results are reliable
 * - Medium Confidence (8-14): Route to AI - can benefit from enhanced classification
 * - Very Low Confidence (<3): Skip AI - likely unclassifiable even with AI
 * - No Labels Selected: Route to AI - last chance for classification
 * - Hard Assertions: Skip AI - domain-based results are authoritative
 */

import { EmailMessage, ClassificationSession, ExplainabilityTrace } from '../types';

// Interface for the classification input (matching test expectations)
export interface EmailClassification {
  gmail_id: string;
  session_id: string;
  selected_labels: SelectedLabel[];
  candidate_scores: Record<string, CandidateScore>;
}

export interface SelectedLabel {
  category: string;
  confidence: number;
  is_primary: boolean;
  subtype?: string;
  reasoning: string;
}

export interface CandidateScore {
  score: number;
  confidence: number;
  decision: string;
  hard_assertion?: boolean;
}

// Configuration interface
export interface AIRoutingConfig {
  settings: {
    ai_routing: {
      high_confidence_threshold: number;
      ai_required_threshold: number;
      skip_ai_conditions: string[];
    };
  };
  confidence_thresholds: {
    high_confidence: number;
    medium_confidence: number;
    low_confidence: number;
    ai_classification_required: number;
  };
}

// Routing decision result
export interface RoutingDecision {
  route_to_ai: boolean;
  routing_reason: string;
  confidence_assessment: string;
  cost_consideration: string;
}

// Stage result interface
export interface AIRoutingResult {
  routing_decision: RoutingDecision;
  routing_branch: 'ai_classification' | 'direct_to_merge';
  explainability_trace: ExplainabilityTrace;
}

/**
 * AI Routing Stage Implementation
 *
 * Analyzes classification confidence and determines optimal routing strategy
 * for email processing continuation.
 */
export function aiRoutingStage(
  email: EmailMessage,
  session: ClassificationSession,
  classification: EmailClassification,
  config: AIRoutingConfig
): AIRoutingResult {
  const startTime = Date.now();

  // Validate inputs
  validateInputs(email, session, classification, config);

  // Extract routing thresholds with fallbacks
  const highConfidenceThreshold =
    config.settings.ai_routing.high_confidence_threshold || config.confidence_thresholds.high_confidence || 15;

  const aiRequiredThreshold = config.confidence_thresholds.medium_confidence || 8;

  const lowConfidenceThreshold = config.confidence_thresholds.low_confidence || 3;

  const skipAiConditions = config.settings.ai_routing.skip_ai_conditions || [];

  // Make routing decision
  const routingDecision = makeRoutingDecision(
    classification.selected_labels,
    classification.candidate_scores,
    highConfidenceThreshold,
    aiRequiredThreshold,
    lowConfidenceThreshold,
    skipAiConditions
  );

  // Generate explainability trace
  const explainabilityTrace = generateExplainabilityTrace(
    classification,
    routingDecision,
    {
      high_confidence_threshold: highConfidenceThreshold,
      ai_required_threshold: aiRequiredThreshold,
      low_confidence_threshold: lowConfidenceThreshold,
    },
    startTime
  );

  return {
    routing_decision: routingDecision,
    routing_branch: routingDecision.route_to_ai ? 'ai_classification' : 'direct_to_merge',
    explainability_trace: explainabilityTrace,
  };
}

/**
 * Validate input parameters
 */
function validateInputs(
  email: EmailMessage,
  session: ClassificationSession,
  classification: EmailClassification,
  config: AIRoutingConfig
): void {
  if (!email?.gmail_id) {
    throw new Error('Invalid email: gmail_id is required');
  }

  if (!session?.session_id) {
    throw new Error('Invalid session: session_id is required');
  }

  if (!classification) {
    throw new Error('Classification is required');
  }

  if (!config) {
    throw new Error('Configuration is required');
  }

  // Validate confidence scores
  if (classification.selected_labels) {
    for (const label of classification.selected_labels) {
      if (isNaN(label.confidence) || !isFinite(label.confidence)) {
        throw new Error('Invalid confidence score');
      }
    }
  }
}

/**
 * Core routing decision logic
 */
function makeRoutingDecision(
  selectedLabels: SelectedLabel[],
  candidateScores: Record<string, CandidateScore>,
  highConfidenceThreshold: number,
  aiRequiredThreshold: number,
  lowConfidenceThreshold: number,
  skipAiConditions: string[]
): RoutingDecision {
  // Case 1: No labels selected - route to AI for last chance classification
  if (selectedLabels.length === 0) {
    return {
      route_to_ai: true,
      routing_reason: 'No labels selected - AI classification may recover classification',
      confidence_assessment: 'no_classification',
      cost_consideration: 'recovery_attempt',
    };
  }

  // Case 2: Check for hard assertions (skip AI condition)
  if (skipAiConditions.includes('hard_assertion')) {
    const hasHardAssertion = Object.values(candidateScores).some((score) => score.hard_assertion);
    if (hasHardAssertion) {
      return {
        route_to_ai: false,
        routing_reason: 'hard assertion applied - domain-based classification is authoritative',
        confidence_assessment: 'hard_assertion_skip',
        cost_consideration: 'ai_unnecessary',
      };
    }
  }

  // Case 3: Check primary label confidence
  const primaryLabel = selectedLabels.find((label) => label.is_primary) || selectedLabels[0];
  const primaryScore = primaryLabel.confidence;

  // High confidence - skip AI (rule-based results are reliable)
  if (primaryScore >= highConfidenceThreshold) {
    return {
      route_to_ai: false,
      routing_reason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
      confidence_assessment: 'high_confidence',
      cost_consideration: 'ai_unnecessary',
    };
  }

  // Very low confidence - skip AI (likely unclassifiable)
  if (primaryScore < lowConfidenceThreshold) {
    return {
      route_to_ai: false,
      routing_reason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
      confidence_assessment: 'very_low_confidence',
      cost_consideration: 'ai_ineffective',
    };
  }

  // Medium confidence range - analyze further for AI routing decision
  const hasMultipleLabels = selectedLabels.length > 1;
  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);

  // Route to AI if in uncertain range and conditions suggest AI could help
  if (primaryScore >= lowConfidenceThreshold && primaryScore < highConfidenceThreshold) {
    let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
    let costConsideration = 'beneficial_enhancement';

    // Additional factors for AI routing decision (prioritize multiple labels over close competitors)
    if (hasCloseCompetitors) {
      aiRoutingReason += ' with close competing categories';
      costConsideration = 'disambiguation_valuable';
    }

    if (hasMultipleLabels) {
      aiRoutingReason += ' with multiple labels selected';
      costConsideration = 'multi_label_validation';
    }

    // Conservative approach: medium confidence usually benefits from AI
    if (primaryScore >= aiRequiredThreshold) {
      return {
        route_to_ai: true,
        routing_reason: aiRoutingReason + ' - AI classification can improve accuracy',
        confidence_assessment: 'medium_confidence',
        cost_consideration: costConsideration,
      };
    } else {
      return {
        route_to_ai: false,
        routing_reason: aiRoutingReason + ' but below AI routing threshold - accept rule-based result',
        confidence_assessment: 'low_medium_confidence',
        cost_consideration: 'cost_threshold_not_met',
      };
    }
  }

  // Default case (shouldn't reach here with proper thresholds)
  return {
    route_to_ai: false,
    routing_reason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
    confidence_assessment: 'unclear',
    cost_consideration: 'default_conservative',
  };
}

/**
 * Check if there are close competing categories that AI could help disambiguate
 */
function checkCloseCompetitors(
  candidateScores: Record<string, CandidateScore>,
  primaryScore: number,
  competitorGap: number = 3
): boolean {
  const competitors = Object.entries(candidateScores)
    .map(([categoryCode, scoreData]) => ({
      category: categoryCode,
      score: scoreData.score || 0,
    }))
    .filter((cat) => cat.score > 0 && cat.score < primaryScore)
    .filter((cat) => primaryScore - cat.score <= competitorGap);

  return competitors.length > 0;
}

/**
 * Generate comprehensive explainability trace
 */
function generateExplainabilityTrace(
  classification: EmailClassification,
  routingDecision: RoutingDecision,
  thresholds: {
    high_confidence_threshold: number;
    ai_required_threshold: number;
    low_confidence_threshold: number;
  },
  startTime: number
): ExplainabilityTrace {
  const processingTime = Date.now() - startTime;
  const primaryLabel = classification.selected_labels.find((l) => l.is_primary) || classification.selected_labels[0];

  return {
    stage_type: 'ai_routing',
    stage_order: 8,
    decision_factors: {
      primary_score: primaryLabel?.confidence || 0,
      threshold_analysis: {
        high_confidence_threshold: thresholds.high_confidence_threshold,
        ai_required_threshold: thresholds.ai_required_threshold,
        low_confidence_threshold: thresholds.low_confidence_threshold,
        primary_score: primaryLabel?.confidence || 0,
        threshold_met: primaryLabel?.confidence >= thresholds.ai_required_threshold ? 'ai_required' : 'below_threshold',
      },
      competitor_analysis: {
        close_competitors_found: checkCloseCompetitors(classification.candidate_scores, primaryLabel?.confidence || 0),
        competitor_count: Object.keys(classification.candidate_scores).length - 1,
        multiple_labels_selected: classification.selected_labels.length > 1,
      },
    },
    reasoning: routingDecision.routing_reason,
    processing_metadata: {
      processing_time_ms: processingTime,
      input_labels_count: classification.selected_labels.length,
      candidate_scores_count: Object.keys(classification.candidate_scores).length,
    },
  };
}

